// ══════════════════════════════════════════════════════════════
// KONFIGURATION - HIER ANPASSEN!
// ══════════════════════════════════════════════════════════════

// Home Assistant REST API
flow.set('haUrl', 'http://homeassistant.local:8123');
flow.set('haToken', 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJiZTE4ZTMwMTk1YzI0OGU1YjdjZjJjNWU3YjVhNjY1NyIsImlhdCI6MTc3MzA0NDA5MywiZXhwIjoyMDg4NDA0MDkzfQ.QQxCkXdmKawHQWPEw8wU4jGWOq1-0qAnBrNBdbvFrBg');

// Modbus Hub Name (aus configuration.yaml)
flow.set('modbusHub', 'Maico KWL');

// Zeitfenster
flow.set('tageszeitStart', 6.0);
flow.set('tageszeitEnde', 21.0);
flow.set('nachtzeitStart', 21.0);   
flow.set('nachtzeitEnde', 5.0);

// Volumenstrom
flow.set('flowRateEnabled', true);
flow.set('flowRateMin', 80);
flow.set('flowRateMax', 210);
flow.set('flowRateStep', 5);
flow.set('flowRateMaxStep', 20);
flow.set('flowRateNightMax', 200);  

// Raumtemperatur-Sensoren

flow.set('roomSensors', [
    { id: 'sensor.wh2650a_temperature_3',      name: 'Wohnzimmer',  target: 22.5, weight: 1.75 },
    { id: 'sensor.wh2650a_indoor_temperature', name: 'Schlafzimmer', target: 20.5, weight: 1.5 },
    { id: 'sensor.wh2650a_temperature_8',      name: 'Kinderzimmer', target: 20.5, weight: 2.5 }
]);

// Absolute Feuchte
flow.set('absHumKinderzimmer',   'sensor.thermal_comfort_kinderzimmer_absolute_luftfeuchtigkeit');
flow.set('taupunktKinderzimmer', 'sensor.thermal_comfort_kinderzimmer_taupunkt');

// Feuchtigkeits-Sensoren
flow.set('humidityBathroom', 'sensor.wh2650a_humidity_7');
flow.set('humidityOutdoor',  'sensor.wh2650a_humidity');
flow.set('humidityIndoor',   'sensor.wh2650a_indoor_humidity');

// Duschenerkennung
flow.set('showerEnabled', true);
flow.set('showerThresholdMild',   8);
flow.set('showerThresholdStrong', 15);
flow.set('showerBoostMild',   40);
flow.set('showerBoostStrong', 80);

// NACHHER:
flow.set('bypassOpenOffset',  1.5);   // Bypass öffnet früher
flow.set('bypassCloseOffset', 1.5);   // Bypass schließt nicht zu aggressiv
flow.set('bypassSeasons', ['spring', 'summer', 'autumn']);  // Auch Herbst

// Jahreszeiten
flow.set('seasons', {
    spring: { start: '03-20', end: '06-20' },
    summer: { start: '06-21', end: '09-22' },
    autumn: { start: '09-23', end: '12-20' },
    winter: { start: '12-21', end: '03-19' }
});

// Debug
flow.set('debugMode', false);

node.log('Konfiguration gespeichert');
msg.payload = 'Konfiguration geladen';
return msg;

context.set('lastMode', null);
context.set('lastFlowRate', null);
context.set('lastSeason', null);
context.set('lastRoomTempMax', null);
context.set('sent_reg_552', null);
context.set('sent_reg_302', null);
context.set('sent_reg_550', null);
context.set('sent_reg_155', null);

flow.set('kwl_prev_bath_rh', null);
node.warn('System zurückgesetzt');
msg.payload = 'Reset OK';
return msg;

var states = global.get('homeassistant.homeAssistant.states') || {};
var DEBUG = flow.get('debugMode') || false;

function getState(id) { return states[id] ? states[id].state : null; }
function getNum(id, fb) { var v = parseFloat(getState(id)); return isNaN(v) ? (fb || null) : v; }

var roomSensors = flow.get('roomSensors') || [];

var data = {
    outdoorTemp: getNum('sensor.wh2650a_outdoor_temperature'),
    currentMode: parseInt(getState('sensor.maico_betriebsart')),
    currentFlowRate: getNum('sensor.maico_aktueller_volumenstrom_zul', 0),
    currentFlowRateExhaust: getNum('sensor.maico_aktueller_volumenstrom_abl', 0),
    bathroomHumidity: getNum(flow.get('humidityBathroom')),
    outdoorHumidity: getNum(flow.get('humidityOutdoor')),
    indoorHumidity: getNum(flow.get('humidityIndoor')),
    filterAlarm: getState('sensor.kwl_filteralarm') === 'alarm',
    rooms: [],
    timestamp: new Date().toISOString()
};
data.absHumOutdoor = getNum('sensor.thermal_comfort_absolute_luftfeuchtigkeit');
data.absHumIndoor = getNum('sensor.thermal_comfort_wohnzimmer_absolute_luftfeuchtigkeit');
data.absHumKinderzimmer = getNum(flow.get('absHumKinderzimmer'));
data.taupunktKinderzimmer = getNum(flow.get('taupunktKinderzimmer'));
data.lufteintrittTemp = getNum('sensor.maico_temperatur_lufteintritt');
// oder je nach Sensor-Wert z.B. '1'/'0' oder 'open'/'closed'
// → anpassen auf den tatsächlichen Wert des Sensors
// NEU v2.3: Zuluft-Temperatur nach Wärmetauscher/Bypass
data.zuluftTemp = getNum('sensor.maico_temperatur_zuluft');
data.bypassOffen = getState('sensor.kwl_bypass') === 'Bypass Auf';

var validRooms = 0;
roomSensors.forEach(function(sensor) {
    var temp = getNum(sensor.id);
    if (temp !== null && temp >= 10 && temp <= 35) {
        data.rooms.push({ id: sensor.id, name: sensor.name, temp: temp, target: sensor.target, weight: sensor.weight });
        validRooms++;
    } else if (temp !== null) {
        node.warn('Sensor ' + sensor.name + ' außerhalb Bereich: ' + temp + '°C (ignoriert)');
    }
});

if (data.currentMode === 5 && data.currentFlowRate === 0 && data.currentFlowRateExhaust > 0) {
    data.currentFlowRate = data.currentFlowRateExhaust;
} else if (data.currentFlowRate === 0) {
    data.currentFlowRate = 150;
}

if (data.outdoorTemp === null || data.outdoorTemp < -40 || data.outdoorTemp > 50) {
    node.error('Ungueltige Aussentemperatur: ' + data.outdoorTemp);
    node.status({ fill: 'red', shape: 'ring', text: 'Sensor-Fehler Außentemp' });
    return null;
}

if (validRooms === 0) {
    node.error('Keine gültigen Raumsensoren!');
    node.status({ fill: 'red', shape: 'ring', text: 'Keine Raumsensoren' });
    return null;
}

node.status({ fill: 'green', shape: 'dot', text: validRooms + ' Räume | ' + data.outdoorTemp + '°C | Zuluft ' + (data.zuluftTemp || '?') + '°C | Modus ' + data.currentMode });
msg.payload = data;

var shadingStatus = global.get('shading_status') || {};
var dwdForecast = shadingStatus.forecastTemp || null;
var forecastDetails = flow.get('dwd_forecast_details') || {};

data.forecast = {
    maxTemp:       dwdForecast,
    condition:     forecastDetails.condition     || null,
    precipitation: forecastDetails.precipitation || 0,
    cloudCover:    shadingStatus.cloudCover      || null,
    source:        dwdForecast ? 'shading_global' : 'none'
};
return msg;

// ══════════════════════════════════════════════════════════════
// STEP 2: STEUERUNGSLOGIK
// Version: 2.5.0 — KfW40+ Delta-Schwelle für Bypass vs Eco-Abluft
// Änderungen gegenüber v2.4.9:
//   - NEU: Mindest-Delta 2.5K für Bypass-Kühlung (KfW40+ optimiert)
//          Bei kleinerem Delta → Eco-Abluft (kühle Raumluft konservieren)
//   - FIX: Hardware-Lock nur wenn Delta < 2.5K UND Außen >= Schwelle
//          (nicht mehr pauschal ab 20.5°C)
//   - Eco-Abluft weiterhin Tag+Nacht aktiv (v2.4.9)
//   - Bypass öffnet nur noch wenn sich Kühlung wirklich lohnt
// ══════════════════════════════════════════════════════════════

var d = msg.payload || {};
var DEBUG = flow.get('debugMode') || false;

// ── Konfiguration laden ───────────────────────────────────────
var config = {
    tageszeitStart: flow.get('tageszeitStart'),
    tageszeitEnde:  flow.get('tageszeitEnde'),
    nachtzeitStart: flow.get('nachtzeitStart'),
    nachtzeitEnde:  flow.get('nachtzeitEnde'),
    flow: {
        min:      flow.get('flowRateMin'),
        max:      flow.get('flowRateMax'),
        step:     flow.get('flowRateStep'),
        maxStep:  flow.get('flowRateMaxStep'),
        nightMax: flow.get('flowRateNightMax')
    },
    shower: {
        enabled: flow.get('showerEnabled'),
        tMild:   flow.get('showerThresholdMild'),
        tStrong: flow.get('showerThresholdStrong'),
        bMild:   flow.get('showerBoostMild'),
        bStrong: flow.get('showerBoostStrong')
    }
};

var ECO_ABLUFT_SCHWELLE = flow.get('ecoAbluftSchwelle') || 20.5;

// KfW40+ Mindest-Delta für sinnvolle Bypass-Kühlung
// Unter diesem Delta bringt Bypass kaum Kühlung, tauscht aber kühle Raumluft aus
var BYPASS_MIN_DELTA = 2.5;

var BYPASS_OPEN_OFFSET  = d.bypassOpenOffsetEffective  || flow.get('bypassOpenOffset')  || 1.5;
var BYPASS_CLOSE_OFFSET = d.bypassCloseOffsetEffective || flow.get('bypassCloseOffset') || 1.5;
var nightBoostMultiplier = (d.forecastModifiers && d.forecastModifiers.nightBoostMultiplier) || 1.0;

var MAX_SCHWELLE = 210;
var BYPASS_ZULUFT_MIN = 8.0;
var BYPASS_RESTERHITZUNG_MIN = 20.0;

// ── Status & Zeit ─────────────────────────────────────────────
var lastMode       = context.get('lastMode')       || d.currentMode;
var lastFlowRate   = context.get('lastFlowRate')   || d.currentFlowRate || 150;
var lastTargetFlow = context.get('lastTargetFlow') || lastFlowRate;

var now = new Date();
var currentTime = now.getHours() + (now.getMinutes() / 60);
var isNight = currentTime >= config.nachtzeitStart || currentTime < config.nachtzeitEnde;

var modeNames = { 0: 'Aus', 1: 'Manuell', 2: 'Auto Zeit', 3: 'Auto Sensor', 4: 'Eco-Zuluft', 5: 'Eco-Abluft' };

// ── Raumanalyse ───────────────────────────────────────────────
var totalDeviation = 0;
var totalWeight    = 0;
(d.rooms || []).forEach(function (r) {
    totalDeviation += (r.temp - r.target) * r.weight;
    totalWeight    += r.weight;
});
var avgTempDeviation = totalWeight > 0 ? totalDeviation / totalWeight : 0;
var avgIndoorTemp = d.rooms.reduce(function (s, r) { return s + r.temp; }, 0) / d.rooms.length;

// Zentrales Delta für alle Entscheidungen
var bypassDelta = avgIndoorTemp - d.outdoorTemp;

// ── Jahreszeit ────────────────────────────────────────────────
function getSeason() {
    var md = (now.getMonth() + 1).toString().padStart(2, '0') + '-' + now.getDate().toString().padStart(2, '0');
    var s = flow.get('seasons');
    var seasonOrder = ['spring', 'summer', 'autumn', 'winter'];
    for (var i = 0; i < seasonOrder.length; i++) {
        var n = seasonOrder[i];
        if (!s[n]) continue;
        if (s[n].start <= s[n].end) {
            if (md >= s[n].start && md <= s[n].end) return n;
        } else {
            if (md >= s[n].start || md <= s[n].end) return n;
        }
    }
    return 'winter';
}
var currentSeason = getSeason();
var bypassAllowed = (flow.get('bypassSeasons') || []).indexOf(currentSeason) >= 0;

// ── Bypass-Erlaubnis: Taupunkt + Zuluft-Mindesttemperatur ─────
var bypassZuluftGesperrt = false;
var taupunktMarginUsed = 1.0;

// v2.4.8: Taupunkt-Check mit Lufteintritt + dynamischem Margin
if (d.taupunktKinderzimmer !== null && d.taupunktKinderzimmer !== undefined) {
    var taupunktRef = d.lufteintrittTemp !== null && d.lufteintrittTemp !== undefined
        ? d.lufteintrittTemp
        : d.outdoorTemp;
    var taupunktRefSource = (taupunktRef === d.lufteintrittTemp) ? 'Eintritt' : 'Aussen';

    taupunktMarginUsed = 1.0;
    if ((currentSeason === 'summer' || currentSeason === 'spring') && avgTempDeviation > 1.0) {
        taupunktMarginUsed = 0.5;
    }

    if (taupunktRef < d.taupunktKinderzimmer + taupunktMarginUsed) {
        bypassAllowed = false;
        if (DEBUG) node.log('Bypass gesperrt: ' + taupunktRefSource
            + ' ' + taupunktRef.toFixed(1) + '°C < Taupunkt+'
            + taupunktMarginUsed + ' (' + (d.taupunktKinderzimmer + taupunktMarginUsed).toFixed(1) + '°C)');
    }
} else {
    if (d.outdoorTemp < 5.0) bypassAllowed = false;
}

// Zuluft-Feedback als Bypass-Bremse
if (d.zuluftTemp !== null && d.zuluftTemp !== undefined && d.zuluftTemp < BYPASS_ZULUFT_MIN) {
    bypassAllowed = false;
    bypassZuluftGesperrt = true;
    if (DEBUG) node.log('Bypass gesperrt: Zuluft ' + d.zuluftTemp + '°C < ' + BYPASS_ZULUFT_MIN + '°C');
}

// ── Hardware-Lock: Bypass nur bei ausreichendem Kühlpotenzial ──
// v2.5.0: Sperrt Bypass wenn Außen >= Schwelle UND Delta < 2.5K
// Bei 21°C außen und 24°C innen (Delta 3K) → Bypass erlaubt
// Bei 21°C außen und 23°C innen (Delta 2K) → Bypass sinnlos → Lock
var bypassHardwareLock = false;
if (d.outdoorTemp >= ECO_ABLUFT_SCHWELLE && bypassDelta < BYPASS_MIN_DELTA) {
    bypassAllowed = false;
    bypassHardwareLock = true;
    if (DEBUG) node.log('Bypass Lock: außen ' + d.outdoorTemp.toFixed(1) + '°C >= '
        + ECO_ABLUFT_SCHWELLE + '°C, Delta nur ' + bypassDelta.toFixed(1)
        + 'K (< ' + BYPASS_MIN_DELTA + 'K, KfW40+ unwirksam)');
}

// ── Absolute Feuchte Innen (schlechtester Raum) ──────────────
var absHumInnenMin = Math.min(
    d.absHumIndoor !== null && d.absHumIndoor !== undefined ? d.absHumIndoor : 99,
    d.absHumKinderzimmer !== null && d.absHumKinderzimmer !== undefined ? d.absHumKinderzimmer : 99
);
var absHumInnenMinSensor = (absHumInnenMin === d.absHumKinderzimmer) ? 'Kinderzimmer' : 'Wohnzimmer';

var aussenFeuchterAlsInnen = (d.absHumOutdoor !== null && d.absHumOutdoor !== undefined)
    && (d.absHumOutdoor > absHumInnenMin + 0.5);

var taupunktSicher = (d.taupunktKinderzimmer === null || d.taupunktKinderzimmer === undefined)
    || (d.outdoorTemp > d.taupunktKinderzimmer + 1.0);

var anfeuchtungMoeglich = aussenFeuchterAlsInnen
    && taupunktSicher
    && bypassAllowed
    && !isNight;

var AH_NOTFALL  = 6.0;
var AH_KRITISCH = 7.5;
var AH_ZIEL     = 9.0;

var innenZuTrocken_Notfall  = absHumInnenMin < AH_NOTFALL;
var innenZuTrocken_Kritisch = absHumInnenMin < AH_KRITISCH;
var anfeuchtungNochNoetig   = absHumInnenMin < AH_ZIEL;

if (DEBUG) {
    node.log('AH-Innen min: ' + absHumInnenMin.toFixed(1) + ' g/m3 (' + absHumInnenMinSensor + ')'
        + ' | AH-Außen: ' + (d.absHumOutdoor || '?')
        + ' | anfeuchtungMoeglich: ' + anfeuchtungMoeglich
        + ' | Zuluft: ' + (d.zuluftTemp || '?') + '°C'
        + ' | Lufteintritt: ' + (d.lufteintrittTemp || '?') + '°C'
        + ' | Taupunkt: ' + (d.taupunktKinderzimmer || '?') + '°C (Margin ' + taupunktMarginUsed + 'K)'
        + ' | bypassAllowed: ' + bypassAllowed
        + ' | bypassDelta: ' + bypassDelta.toFixed(1) + 'K'
        + ' | zuluftGesperrt: ' + bypassZuluftGesperrt
        + ' | bypassOffen (Sensor): ' + d.bypassOffen);
}

// ── Modus-Logik ───────────────────────────────────────────────
var newMode      = 1;
var bypassWanted = false;
var reason       = 'Standard';

var outsideCooler = d.outdoorTemp <= avgIndoorTemp - BYPASS_OPEN_OFFSET;

// v2.5.0: Eco-Abluft wenn Außen >= Schwelle UND Delta zu klein für Bypass
// ODER wenn Außen wärmer als Innen (klassischer Fall)
var ecoAbluftAktiv = d.outdoorTemp >= ECO_ABLUFT_SCHWELLE
    && bypassDelta < BYPASS_MIN_DELTA
    && avgTempDeviation > 0.3;

if (DEBUG) {
    node.log('Eco-Abluft-Check: außen=' + d.outdoorTemp.toFixed(1)
        + '°C, Schwelle=' + ECO_ABLUFT_SCHWELLE
        + ', bypassDelta=' + bypassDelta.toFixed(1) + 'K'
        + ', minDelta=' + BYPASS_MIN_DELTA
        + ', ecoAbluftAktiv=' + ecoAbluftAktiv
        + ', isNight=' + isNight);
}

// ════════════════════════════════════════════════════════════
// PRIORITÄT 1: Gesundheitsgrenze — AH-Notfall
// ════════════════════════════════════════════════════════════
if (innenZuTrocken_Notfall && anfeuchtungMoeglich) {
    newMode = 4;
    bypassWanted = true;
    reason = 'AH-Notfall: ' + absHumInnenMin.toFixed(1) + ' g/m3 < ' + AH_NOTFALL + ' (' + absHumInnenMinSensor + ')';
    if (DEBUG) node.log('Prio 1 aktiv: ' + reason);

// ════════════════════════════════════════════════════════════
// PRIORITÄT 2: Komfort-Kompromiss (Anfeuchtung)
// ════════════════════════════════════════════════════════════
} else if (innenZuTrocken_Kritisch && anfeuchtungNochNoetig && anfeuchtungMoeglich) {
    newMode = 4;
    bypassWanted = true;
    reason = 'Anfeuchtung' + (avgTempDeviation > 0.3 ? '+Kühl-Kompromiss' : '')
        + ': AH ' + absHumInnenMin.toFixed(1) + ' g/m3 (' + absHumInnenMinSensor + ')';
    if (DEBUG) node.log('Prio 2 aktiv: ' + reason);

// ════════════════════════════════════════════════════════════
// PRIORITÄT 3: Eco-Abluft — zu warm oder Delta zu klein
// v2.5.0: Greift wenn Bypass nichts bringt (Delta < 2.5K bei >= 20.5°C)
// ════════════════════════════════════════════════════════════
} else if (ecoAbluftAktiv) {
    newMode = 5;
    reason = 'Eco-Abluft: außen ' + d.outdoorTemp.toFixed(1) + '°C >= ' + ECO_ABLUFT_SCHWELLE
        + '°C, Delta ' + bypassDelta.toFixed(1) + 'K < ' + BYPASS_MIN_DELTA + 'K (KfW40+ unwirksam), Dev +'
        + avgTempDeviation.toFixed(1) + 'K'
        + (isNight ? ' [Nacht]' : '');

// ════════════════════════════════════════════════════════════
// PRIORITÄT 4: Temperatur-Steuerung Sommer + Übergang
// Hier landen wir NUR wenn Delta >= 2.5K ODER Außen < Schwelle
// ════════════════════════════════════════════════════════════
} else if (currentSeason === 'summer' || avgTempDeviation > 0.5) {

    if (isNight && outsideCooler && bypassAllowed) {
        newMode = 1;
        bypassWanted = true;
        reason = 'Nachtkuehlung Balanced (Delta ' + bypassDelta.toFixed(1) + 'K)';

    } else if (!isNight && outsideCooler && bypassAllowed && avgTempDeviation > 0.3) {
        newMode = 1;
        bypassWanted = true;
        reason = 'Tageskuehlung Balanced (aussen ' + d.outdoorTemp.toFixed(1)
            + ' < innen ' + avgIndoorTemp.toFixed(1) + ', Dev +' + avgTempDeviation.toFixed(1) + 'K, Delta ' + bypassDelta.toFixed(1) + 'K)';

    } else if (!isNight && bypassAllowed
            && d.outdoorTemp >= BYPASS_RESTERHITZUNG_MIN
            && avgTempDeviation > 0.3
            && d.outdoorTemp <= avgIndoorTemp + 1) {
        newMode = 1;
        bypassWanted = true;
        reason = 'WT-Bypass Resterhitzung (aussen ' + d.outdoorTemp.toFixed(1)
            + '°C >= ' + BYPASS_RESTERHITZUNG_MIN + ', Dev +' + avgTempDeviation.toFixed(1) + 'K)';

    } else {
        newMode = 1;
        reason = 'Sommer Balanced (Dev ' + avgTempDeviation.toFixed(1) + 'K'
            + (bypassZuluftGesperrt ? ', Zuluft<' + BYPASS_ZULUFT_MIN + '°C' : '')
            + (bypassHardwareLock ? ', HW-Lock Delta<' + BYPASS_MIN_DELTA + 'K' : '')
            + (!bypassAllowed && !bypassZuluftGesperrt && !bypassHardwareLock ? ', Bypass gesperrt' : '') + ')';
    }

// ════════════════════════════════════════════════════════════
// PRIORITÄT 5: Übergangszeit / Winter ohne starke Abweichung
// ════════════════════════════════════════════════════════════
} else {
    if ((currentSeason === 'spring' || currentSeason === 'autumn') && outsideCooler && bypassAllowed && avgTempDeviation > 0.3) {
        newMode = 1;
        bypassWanted = true;
        reason = 'Uebergang Bypass Balanced (Dev +' + avgTempDeviation.toFixed(1) + 'K, Delta ' + bypassDelta.toFixed(1) + 'K)';

    } else if ((currentSeason === 'spring' || currentSeason === 'autumn') && bypassAllowed
            && d.outdoorTemp >= BYPASS_RESTERHITZUNG_MIN
            && avgTempDeviation > 0.3
            && d.outdoorTemp <= avgIndoorTemp + 1) {
        newMode = 1;
        bypassWanted = true;
        reason = 'Uebergang WT-Bypass Resterhitzung (aussen ' + d.outdoorTemp.toFixed(1)
            + '°C >= ' + BYPASS_RESTERHITZUNG_MIN + ', Dev +' + avgTempDeviation.toFixed(1) + 'K)';

    } else if (currentSeason === 'spring' || currentSeason === 'autumn') {
        newMode = 1;
        reason = 'Uebergang Balanced';

    } else {
        newMode = 1;
        reason = 'Winter Balanced';
    }
}

// ── Bypass-Register 302 ───────────────────────────────────────
var targetRoomTempMax;
if (bypassWanted) {
    var basisSchwelle = (avgIndoorTemp - BYPASS_OPEN_OFFSET) * 10;
    targetRoomTempMax = Math.min(basisSchwelle, MAX_SCHWELLE);

    if (d.zuluftTemp !== null && d.zuluftTemp !== undefined && d.zuluftTemp > d.outdoorTemp + 2) {
        var zuluftBasiert = (d.zuluftTemp - 1.0) * 10;
        targetRoomTempMax = Math.min(targetRoomTempMax, zuluftBasiert);
        if (DEBUG) node.log('Bypass Zuluft-Feedback: Zuluft ' + d.zuluftTemp + '°C → Schwelle ' + (targetRoomTempMax / 10).toFixed(1) + '°C');
    }
} else {
    targetRoomTempMax = (avgIndoorTemp + BYPASS_CLOSE_OFFSET) * 10;
}
targetRoomTempMax = Math.max(180, Math.min(300, Math.round(targetRoomTempMax / 5) * 5));

// ── Bypass-Validierung (echter Sensor primär) ─────────────────
var bypassEffektiv = null;
var validierungSource = 'kwl_bypass Sensor';

if (d.bypassOffen !== null && d.bypassOffen !== undefined) {
    bypassEffektiv = d.bypassOffen === true;

    if (bypassWanted && !bypassEffektiv) {
        node.warn('⚠️ Bypass-Mismatch: gewollt OFFEN, aber Sensor meldet GESCHLOSSEN'
            + ' (Reg.302=' + targetRoomTempMax + ' = ' + (targetRoomTempMax / 10).toFixed(1) + '°C)');
    }
    if (!bypassWanted && bypassEffektiv) {
        if (DEBUG) node.log('Info: Bypass laut Sensor OFFEN obwohl nicht gewollt');
    }

} else {
    validierungSource = d.lufteintrittTemp !== null && d.lufteintrittTemp !== undefined
        ? 'Lufteintritt (Fallback)'
        : 'Wetterstation (Fallback)';
    var validierungRef = d.lufteintrittTemp !== null && d.lufteintrittTemp !== undefined
        ? d.lufteintrittTemp
        : d.outdoorTemp;

    if (d.zuluftTemp !== null && d.zuluftTemp !== undefined && validierungRef !== null) {
        var zuluftDelta = d.zuluftTemp - validierungRef;
        if (bypassWanted) {
            bypassEffektiv = zuluftDelta < 1.0;
            if (!bypassEffektiv && zuluftDelta > 3.0) {
                node.warn('⚠️ Bypass-Mismatch (Heuristik): gewollt OFFEN, Zuluft '
                    + d.zuluftTemp + '°C >> ' + validierungSource + ' '
                    + validierungRef.toFixed(1) + '°C (Delta ' + zuluftDelta.toFixed(1) + 'K)');
            }
        } else {
            bypassEffektiv = zuluftDelta < 2.0;
        }
    }
    if (DEBUG) node.log('Bypass-Sensor nicht verfügbar, Heuristik genutzt');
}

// ── Volumenstrom ──────────────────────────────────────────────
var targetFlowRate = 110;
var flowReasons    = [];
var showerBoostActive = false;

// Thermik-Boost
if (avgTempDeviation > 0) {
    var boost = Math.round(avgTempDeviation * 30);
    targetFlowRate += boost;
    flowReasons.push('Temp: +' + boost);
}

// Nacht-Boost: delta-abhängig
if (bypassWanted && isNight && outsideCooler) {
    var nightDelta = bypassDelta;
    var nightBoostBase = 140;
    if (nightDelta > 7)      nightBoostBase = 200;
    else if (nightDelta > 5) nightBoostBase = 180;
    else if (nightDelta > 3) nightBoostBase = 160;

    var nightBoostTarget = Math.round((nightBoostBase * nightBoostMultiplier) / config.flow.step) * config.flow.step;
    nightBoostTarget = Math.min(nightBoostTarget, config.flow.nightMax);
    targetFlowRate = Math.max(targetFlowRate, nightBoostTarget);
    flowReasons.push('Night-Cool: Delta ' + nightDelta.toFixed(1) + 'K, x' + nightBoostMultiplier.toFixed(2) + ' -> ' + nightBoostTarget + ' m3/h');
}

// Tag-Bypass-Boost inkl. Forecast-Vorkühlung
if (bypassWanted && !isNight && outsideCooler) {
    var dayDelta = bypassDelta;
    var dayBoostTarget = 100;
    if (dayDelta > 7)        dayBoostTarget = 220;
    else if (dayDelta > 5)   dayBoostTarget = 200;
    else if (dayDelta > 3)   dayBoostTarget = 170;
    else if (dayDelta > 1.5) dayBoostTarget = 140;

    // Vorkühlung-Boost bei heißem Forecast (morgens 6-12 Uhr)
    var forecastAggr = (d.forecastModifiers && d.forecastModifiers.bypassAggressiveness) || 0;
    if (forecastAggr >= 1 && currentTime >= 6 && currentTime <= 12) {
        var virtualDelta = dayDelta + (forecastAggr * 2);
        var forecastBoost = 100;
        if (virtualDelta > 7)        forecastBoost = 220;
        else if (virtualDelta > 5)   forecastBoost = 200;
        else if (virtualDelta > 3)   forecastBoost = 170;
        else if (virtualDelta > 1.5) forecastBoost = 140;

        if (forecastBoost > dayBoostTarget) {
            flowReasons.push('Vorkuehlung: Forecast hot (Aggr=' + forecastAggr + '), virtuell +' + (forecastAggr * 2) + 'K -> ' + forecastBoost + ' m3/h');
            dayBoostTarget = forecastBoost;
        }
    }

    // Kalt-Bypass-Cap
    if (d.zuluftTemp !== null && d.zuluftTemp < 12) {
        dayBoostTarget = Math.min(dayBoostTarget, 100);
        flowReasons.push('Kalt-Bypass-Cap: Zuluft ' + d.zuluftTemp + '°C → max 100 m3/h');
    }

    targetFlowRate = Math.max(targetFlowRate, dayBoostTarget);
    flowReasons.push('Tag-Bypass: Delta ' + dayDelta.toFixed(1) + 'K -> ' + dayBoostTarget + ' m3/h');
}

// Dusche
if (config.shower.enabled && d.bathroomHumidity !== null) {
    var prevH      = flow.get('kwl_prev_bath_rh');
    var lastUpdate = flow.get('kwl_prev_bath_time') || 0;
    var nowMs      = Date.now();
    if (prevH === null || nowMs - lastUpdate > 3600000) {
        prevH = d.bathroomHumidity;
        if (DEBUG) node.log('Duschenerkennung initialisiert/zurückgesetzt');
    }
    var deltaH = d.bathroomHumidity - prevH;
    flow.set('kwl_prev_bath_rh',   d.bathroomHumidity);
    flow.set('kwl_prev_bath_time', nowMs);
    if (deltaH >= config.shower.tMild) {
        var sBoost = deltaH >= config.shower.tStrong ? config.shower.bStrong : config.shower.bMild;
        targetFlowRate += sBoost;
        flowReasons.push('Dusche: +' + sBoost);
        showerBoostActive = true;
    }
}

// ── AH-basierter Flow-Cap ─────────────────────────────────────
var ahFlowCap;
if (innenZuTrocken_Notfall && anfeuchtungMoeglich) {
    ahFlowCap = config.flow.min;
    flowReasons.push('AH-Notbremse: ' + absHumInnenMin.toFixed(1) + ' g/m3 → max ' + config.flow.min + ' m3/h');

} else if (innenZuTrocken_Kritisch && anfeuchtungMoeglich) {
    var kuehlBeitrag = avgTempDeviation > 0 ? Math.round(avgTempDeviation * 20) : 0;
    ahFlowCap = Math.min(120, 80 + kuehlBeitrag);
    flowReasons.push('AH-Bremse: ' + absHumInnenMin.toFixed(1) + ' g/m3 → cap ' + ahFlowCap + ' m3/h');

} else if (anfeuchtungNochNoetig && anfeuchtungMoeglich) {
    ahFlowCap = 150;
    flowReasons.push('AH-sanft: ' + absHumInnenMin.toFixed(1) + ' g/m3 → cap 150 m3/h');

} else if (d.absHumOutdoor !== null && d.absHumIndoor !== null && !anfeuchtungMoeglich) {
    if (d.absHumOutdoor - d.absHumIndoor < -2.0) {
        targetFlowRate = Math.max(config.flow.min, targetFlowRate - 40);
        flowReasons.push('Trockenschutz: -40 m3/h (außen trockener)');
    }
    ahFlowCap = isNight ? config.flow.nightMax : config.flow.max;

} else {
    ahFlowCap = isNight ? config.flow.nightMax : config.flow.max;
}

// Cap anwenden
targetFlowRate = Math.min(ahFlowCap, targetFlowRate);
targetFlowRate = Math.max(config.flow.min, Math.min(isNight ? config.flow.nightMax : config.flow.max, targetFlowRate));
targetFlowRate = Math.round(targetFlowRate / config.flow.step) * config.flow.step;

// Hysterese
if (Math.abs(targetFlowRate - lastTargetFlow) < 8 && !showerBoostActive) {
    targetFlowRate = lastTargetFlow;
} else {
    context.set('lastTargetFlow', targetFlowRate);
}

// Max Step pro Zyklus
var diff = targetFlowRate - lastFlowRate;
if (Math.abs(diff) > config.flow.maxStep) {
    targetFlowRate = lastFlowRate + (diff > 0 ? config.flow.maxStep : -config.flow.maxStep);
}

// ── Befehle generieren ────────────────────────────────────────
var commands = [];
if (targetRoomTempMax !== context.get('lastRoomTempMax'))
    commands.push({ type: 'roomtempmax', register: 302, value: targetRoomTempMax });
if ((bypassAllowed ? 1 : 0) !== context.get('lastSeasonReg'))
    commands.push({ type: 'season', register: 552, value: bypassAllowed ? 1 : 0 });
if (targetFlowRate !== lastFlowRate)
    commands.push({ type: 'flowrate', register: 155, value: targetFlowRate });
if (newMode !== lastMode)
    commands.push({ type: 'mode', register: 550, value: newMode });

context.set('lastMode',        newMode);
context.set('lastFlowRate',    targetFlowRate);
context.set('lastRoomTempMax', targetRoomTempMax);
context.set('lastSeasonReg',   bypassAllowed ? 1 : 0);

// ── Ausgabe ───────────────────────────────────────────────────
msg.payload = {
    commands: commands,
    mode: { name: modeNames[newMode], reason: reason },
    flowRate: {
        new:     targetFlowRate,
        old:     lastFlowRate,
        delta:   targetFlowRate - lastFlowRate,
        reasons: flowReasons,
        ahCap:   ahFlowCap
    },
    absHum: {
        out:    d.absHumOutdoor,
        in:     d.absHumIndoor,
        kinder: d.absHumKinderzimmer,
        innenMin:       absHumInnenMin.toFixed(1),
        innenMinSensor: absHumInnenMinSensor,
        diff: (d.absHumOutdoor !== null && d.absHumIndoor !== null)
            ? (d.absHumOutdoor - d.absHumIndoor).toFixed(2) : '?',
        diffKinder: (d.absHumOutdoor !== null && d.absHumKinderzimmer !== null)
            ? (d.absHumOutdoor - d.absHumKinderzimmer).toFixed(2) : '?',
        anfeuchtung: {
            moeglich:       anfeuchtungMoeglich,
            aussenFeuchter: aussenFeuchterAlsInnen,
            taupunktSicher: taupunktSicher,
            notfall:        innenZuTrocken_Notfall,
            kritisch:       innenZuTrocken_Kritisch,
            nochNoetig:     anfeuchtungNochNoetig
        }
    },
    bypass: {
        wanted:           bypassWanted,
        effektiv:         bypassEffektiv,
        sensorDirekt:     d.bypassOffen !== null && d.bypassOffen !== undefined,
        hardwareLock:     bypassHardwareLock,
        reg302:           targetRoomTempMax,
        maxSchwelle:      MAX_SCHWELLE,
        openOffset:       BYPASS_OPEN_OFFSET,
        closeOffset:      BYPASS_CLOSE_OFFSET,
        outsideCooler:    outsideCooler,
        deltaT:           bypassDelta.toFixed(1),
        minDelta:         BYPASS_MIN_DELTA,
        zuluftTemp:       d.zuluftTemp,
        lufteintrittTemp: d.lufteintrittTemp,
        validierungSource: validierungSource,
        zuluftGesperrt:   bypassZuluftGesperrt,
        zuluftMin:        BYPASS_ZULUFT_MIN,
        taupunkt:         d.taupunktKinderzimmer,
        taupunktMargin:   taupunktMarginUsed
    },
    ecoAbluft: {
        aktiv:      ecoAbluftAktiv,
        schwelle:   ECO_ABLUFT_SCHWELLE,
        minDelta:   BYPASS_MIN_DELTA,
        bypassDelta: bypassDelta.toFixed(1),
        aussenTemp: d.outdoorTemp,
        isNight:    isNight
    },
    forecastModifiers: d.forecastModifiers || { reason: ['keine Modifier'] },
    roomLog:          (d.rooms || []).map(function (r) { return r.name + ': ' + r.temp.toFixed(1) + '\u00b0C'; }).join(' | '),
    season:           currentSeason,
    isNight:          isNight,
    avgTempDeviation: avgTempDeviation.toFixed(2),
    reg302_display:   targetRoomTempMax
};

return msg;

var p = msg.payload || {};
if (!p.commands || p.commands.length === 0) return null;

// FIX #8: Token aus Umgebungsvariable statt Klartext
var HA_URL = flow.get('haUrl');
var HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken'); // Fallback auf flow.get
var MODBUS_HUB = flow.get('modbusHub');

var apiCalls = [];

p.commands.forEach(function (cmd) {
    var contextKey = 'sent_reg_' + cmd.register;
    var lastSentValue = context.get(contextKey);

    if (cmd.value !== lastSentValue) {
        if (cmd.type === 'flowrate') {
            // FIX #9: Nur beim ersten Mal die Fix-Register setzen
            if (!context.get('flowrate_initialized')) {
                if (context.get('sent_reg_154') !== 80) 
                    apiCalls.push({ address: 154, value: 80, desc: 'Fix Reduziert' });
                if (context.get('sent_reg_156') !== 300) 
                    apiCalls.push({ address: 156, value: 300, desc: 'Fix Intensiv' });
                if (context.get('sent_reg_554') !== 3) 
                    apiCalls.push({ address: 554, value: 3, desc: 'Stufe 3' });
                context.set('flowrate_initialized', true);
            }
            apiCalls.push({ address: 155, value: cmd.value, desc: 'Flow ' + cmd.value });
        } else {
            apiCalls.push({ address: cmd.register, value: cmd.value, desc: 'Reg ' + cmd.register + ' -> ' + cmd.value });
        }
    }
});

if (apiCalls.length === 0) return null;

flow.set('kwl_api_queue', apiCalls.slice(1));
flow.set('kwl_api_total', apiCalls.length);
flow.set('kwl_api_done', 0);

var first = apiCalls[0];
context.set('sent_reg_' + first.address, first.value);

msg.url = HA_URL + '/api/services/modbus/write_register';
msg.method = 'POST';
msg.headers = { 'Authorization': 'Bearer ' + HA_TOKEN, 'Content-Type': 'application/json' };
msg.payload = { hub: MODBUS_HUB, slave: 1, address: first.address, value: [first.value] };

node.status({ fill: 'blue', shape: 'dot', text: 'Sende ' + first.desc });
return [msg, null];

var done = flow.get('kwl_api_done') || 0;
done++;
flow.set('kwl_api_done', done);

var total = flow.get('kwl_api_total') || 0;
var queue = flow.get('kwl_api_queue') || [];
var DEBUG = flow.get('debugMode') || false;

// FIX #8: Bei Fehler Queue leeren
if (msg.statusCode !== 200) {
    node.error('Call ' + done + '/' + total + ' FEHLER: ' + msg.statusCode + ' - ' + msg.payload);
    flow.set('kwl_api_queue', []); // Queue leeren
    node.status({ fill: 'red', shape: 'ring', text: 'API-Fehler ' + msg.statusCode });
    return null;
}

if (DEBUG) { node.log('Call ' + done + '/' + total + ' OK'); }

if (queue.length === 0) {
    node.status({ fill: 'green', shape: 'dot', text: done + '/' + total + ' fertig' });
    return null;
}

var next = queue[0];
flow.set('kwl_api_queue', queue.slice(1));

var HA_URL = flow.get('haUrl') || 'http://homeassistant.local:8123';
var HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken');
var MODBUS_HUB = flow.get('modbusHub') || 'Maico KWL';

msg.url = HA_URL + '/api/services/modbus/write_register';
msg.method = 'POST';
msg.headers = {};
msg.headers['Authorization'] = 'Bearer ' + HA_TOKEN;
msg.headers['Content-Type'] = 'application/json';
msg.payload = '{"hub":"' + MODBUS_HUB + '","slave":1,"address":' + next.address + ',"value":[' + next.value + ']}';

delete msg.statusCode;
delete msg.responseUrl;
delete msg.redirectList;

if (DEBUG) { node.log('Sende ' + (done + 1) + '/' + total + ': ' + next.desc); }

node.status({ fill: 'blue', shape: 'dot', text: 'Sende ' + (done + 1) + '/' + total + ': ' + next.desc });

return msg;

var HA_URL = flow.get('haUrl') || 'http://homeassistant.local:8123';
var HA_TOKEN = flow.get('haToken') || '';
var MODBUS_HUB = flow.get('modbusHub') || 'Maico KWL';

msg.url = HA_URL + '/api/services/modbus/write_register';
msg.method = 'POST';
msg.headers = {};
msg.headers['Authorization'] = 'Bearer ' + HA_TOKEN;
msg.headers['Content-Type'] = 'application/json';
msg.payload = '{"hub":"' + MODBUS_HUB + '","slave":1,"address":302,"value":[210]}';

node.warn('Test Reg.302 (T-Raum max = 21.0°C): ' + msg.payload);
return msg;

flow.set('debugMode', msg.payload);
node.warn('Debug: ' + (msg.payload ? 'AN' : 'AUS'));
msg.payload = 'Debug ' + (msg.payload ? 'AN' : 'AUS');
return msg;

var p = msg.payload || {};
var HA_URL = flow.get('haUrl');
var HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken');

var forceLog = (p.bypass && p.bypass.effektiv === false && p.bypass.wanted === true);
if ((!p.commands || p.commands.length === 0) && !forceLog) return null;

function f(val, n) {
    var num = parseFloat(val);
    return isNaN(num) ? '?' : num.toFixed(n !== undefined ? n : 1);
}

var regLabels = {
    550: 'Betriebsart',
    552: 'Bypass-Saison',
    302: 'Bypass-Temp',
    155: 'Volumenstrom',
    154: 'Flow-Reduziert',
    156: 'Flow-Intensiv',
    554: 'Stufe'
};
var modeLabels = { 0: 'Aus', 1: 'Manuell', 2: 'AutoZeit', 3: 'AutoSensor', 4: 'Eco-Zu', 5: 'Eco-Ab' };

var parts = [];
(p.commands || []).forEach(function (cmd) {
    var label = regLabels[cmd.register] || ('Reg' + cmd.register);
    var val = cmd.value;
    if (cmd.register === 550) val = (modeLabels[cmd.value] || cmd.value);
    if (cmd.register === 552) val = (cmd.value === 1 ? 'ein' : 'aus');
    if (cmd.register === 302) val = (cmd.value / 10).toFixed(1) + '\u00b0C';
    if (cmd.register === 155 || cmd.register === 154 || cmd.register === 156)
        val = cmd.value + ' m\u00b3/h';
    parts.push(label + '\u2192' + val);
});

var flowReasons = (p.flowRate && p.flowRate.reasons || []).join(', ') || 'keine';
var absHum = p.absHum || {};
var bypass = p.bypass || {};
var anfeuch = absHum.anfeuchtung || {};

var rooms = (p.roomLog || '').replace(/(\d+\.\d{2,})/g, function (m) {
    return parseFloat(m).toFixed(1);
});

var anfeuchtStatus;
if (anfeuch.notfall) anfeuchtStatus = 'NOTFALL';
else if (anfeuch.kritisch) anfeuchtStatus = 'kritisch';
else if (anfeuch.nochNoetig) anfeuchtStatus = 'aktiv';
else anfeuchtStatus = 'ok';

// Bypass-Effektiv nur relevant wenn gewollt
var bypassEffektivText;
if (bypass.wanted && bypass.effektiv === true) bypassEffektivText = 'JA';
else if (bypass.wanted && bypass.effektiv === false) bypassEffektivText = 'NEIN!';
else bypassEffektivText = '-';

// ── Fenster-Empfehlung berechnen ──────────────────────────────
var sensorData = flow.get('kwl_last_sensor_data') || {};
var outTemp = sensorData.outdoorTemp || 0;
var avgIndoorTemp = 0;
var roomCount = 0;
(sensorData.rooms || []).forEach(function (r) {
    avgIndoorTemp += r.temp;
    roomCount++;
});
if (roomCount > 0) avgIndoorTemp = avgIndoorTemp / roomCount;

var absHumOut = parseFloat(absHum.out) || null;
var absHumIn = parseFloat(absHum.innenMin) || null;
var taupunktSicher = anfeuch.taupunktSicher !== false;
var isNight = p.isNight || false;

var deltaT = avgIndoorTemp - outTemp;

var feuchteOk = true;
if (absHumOut !== null && absHumIn !== null) {
    feuchteOk = absHumOut <= absHumIn + 1.5;
}

var fensterIcon;
var fensterText;

if (deltaT >= 3 && feuchteOk && taupunktSicher && !isNight) {
    fensterIcon = '\ud83d\udfe2';
    fensterText = 'Fenster auf (' + deltaT.toFixed(0) + 'K k\u00fchler)';
} else if (deltaT >= 1 && feuchteOk && taupunktSicher) {
    fensterIcon = '\ud83d\udfe1';
    fensterText = 'Kipp ok (' + deltaT.toFixed(0) + 'K)';
    if (isNight) fensterText += ' [Nacht]';
} else if (deltaT < 0) {
    fensterIcon = '\ud83d\udd34';
    fensterText = 'Fenster zu! (au\u00dfen w\u00e4rmer)';
} else if (!feuchteOk) {
    fensterIcon = '\ud83d\udd34';
    fensterText = 'Fenster zu! (au\u00dfen zu feucht)';
} else if (!taupunktSicher) {
    fensterIcon = '\ud83d\udd34';
    fensterText = 'Fenster zu! (Kondensation)';
} else {
    fensterIcon = '\ud83d\udfe1';
    fensterText = 'Kurz kippen ok (' + deltaT.toFixed(0) + 'K)';
}

// v2.4.1: Validierungsquelle im Log anzeigen
var bypassValidText = bypass.wanted
    ? ('effektiv: ' + bypassEffektivText + ' (via ' + (bypass.validierungSource || '?') + ')')
    : ('effektiv: ' + bypassEffektivText);

var lines = [
    'Modus: ' + (p.mode && p.mode.name || '?') + ' | Grund: ' + (p.mode && p.mode.reason || '?'),
    'Reg: ' + (parts.join(' | ') || '\u2014'),
    'Flow: ' + flowReasons + ' | Cap: ' + f(p.flowRate && p.flowRate.ahCap, 0) + ' m\u00b3/h',
    'AH: min ' + f(absHum.innenMin, 1) + ' g/m\u00b3 (' + (absHum.innenMinSensor || '?') + ')'
    + ' | Wohnen ' + f(absHum.in, 1)
    + ' | Kinder ' + f(absHum.kinder, 1)
    + ' | Au\u00dfen ' + f(absHum.out, 1),
    'AH Delta: Wohnen ' + f(absHum.diff, 1) + ' | Kinder ' + f(absHum.diffKinder, 1) + ' g/m\u00b3',
    'Anfeuchtung: ' + anfeuchtStatus
    + ' | au\u00dfen feuchter: ' + (anfeuch.aussenFeuchter ? 'ja' : 'nein')
    + ' | m\u00f6glich: ' + (anfeuch.moeglich ? 'ja' : 'nein'),
    'Bypass: ' + (bypass.wanted ? 'OFFEN' : 'ZU')
    + ' | ' + bypassValidText
    + (bypass.zuluftGesperrt ? ' | \u26a0\ufe0f Zuluft<' + f(bypass.zuluftMin, 0) + '\u00b0C!' : '')
    + ' | Schwelle ' + f(bypass.reg302 / 10, 1) + '\u00b0C (max ' + f(bypass.maxSchwelle / 10, 1) + '\u00b0C)'
    + ' | Zuluft ' + f(bypass.zuluftTemp, 1) + '\u00b0C'
    + ' | Eintritt ' + f(bypass.lufteintrittTemp, 1) + '\u00b0C'
    + ' | DeltaT ' + (bypass.deltaT || '?') + 'K'
    + ' | Offset ' + f(bypass.openOffset, 1) + 'K',
    fensterIcon + ' Fenster: ' + fensterText,
    'R\u00e4ume: ' + rooms + ' | TempDev: ' + f(p.avgTempDeviation, 2) + 'K',
    (p.season || '?') + ' | Nacht: ' + (p.isNight ? 'ja' : 'nein')
    + ' | Forecast: ' + ((p.forecastModifiers && p.forecastModifiers.reason
        && p.forecastModifiers.reason.join(', ')) || '\u2014')
];

msg.url = HA_URL + '/api/services/logbook/log';
msg.method = 'POST';
msg.headers = { 'Authorization': 'Bearer ' + HA_TOKEN, 'Content-Type': 'application/json' };
msg.payload = {
    name: 'KWL Steuerung',
    message: lines.join(' // '),
    entity_id: 'sensor.maico_betriebsart',
    domain: 'kwl'
};

return msg;

var d = msg.payload || {};
var fc = d.forecast || {};

var modifiers = {
    bypassAggressiveness: 0,
    refillThresholdOffset: 0,
    nightBoostMultiplier: 1.0,
    reason: []
};

var maxTemp    = fc.maxTemp    || null;
var precip     = fc.precipitation || 0;
var condition  = (fc.condition || '').toLowerCase();
var cloudCover = fc.cloudCover || null;

if (maxTemp !== null) {
    if (maxTemp >= 30) {
        modifiers.bypassAggressiveness = 2;
        modifiers.nightBoostMultiplier = 1.5;
        modifiers.reason.push('Heisstag erwartet (' + maxTemp + '°C): Bypass++ / Nacht-Boost x1.5');
    } else if (maxTemp >= 26) {
        modifiers.bypassAggressiveness = 1;
        modifiers.nightBoostMultiplier = 1.25;
        modifiers.reason.push('Warmer Tag erwartet (' + maxTemp + '°C): Bypass+ / Nacht-Boost x1.25');
    } else if (maxTemp < 18) {
        modifiers.bypassAggressiveness = -1;
        modifiers.reason.push('Kühler Tag erwartet (' + maxTemp + '°C): Bypass konservativ');
    }
}

if (precip > 5) {
    modifiers.refillThresholdOffset = -0.5;
    modifiers.reason.push('Regen erwartet (' + precip + 'mm): Refill-Schwellwert -0.5 g/m³');
} else if (precip > 2) {
    modifiers.refillThresholdOffset = -0.3;
    modifiers.reason.push('Leichter Regen erwartet (' + precip + 'mm): Refill-Schwellwert -0.3 g/m³');
}

var isClear  = condition.indexOf('sunny') >= 0 || condition.indexOf('clear') >= 0 || condition.indexOf('partlycloudy') >= 0;
var isCloudy = condition.indexOf('cloudy') >= 0 || condition.indexOf('overcast') >= 0 || (cloudCover !== null && cloudCover > 70);

if (isClear && maxTemp !== null && maxTemp >= 22) {
    modifiers.nightBoostMultiplier = Math.min(modifiers.nightBoostMultiplier * 1.2, 1.8);
    modifiers.reason.push('Klar/Sonnig: Nacht-Boost x' + modifiers.nightBoostMultiplier.toFixed(2));
} else if (isCloudy) {
    modifiers.nightBoostMultiplier = Math.max(modifiers.nightBoostMultiplier * 0.8, 0.5);
    modifiers.reason.push('Bewölkt: Nacht-Boost x' + modifiers.nightBoostMultiplier.toFixed(2));
}

// FIX #11: Multiplikator-Obergrenze an flowRateNightMax anpassen
var nightMaxFlow = flow.get('flowRateNightMax') || 170;
var maxMultiplier = nightMaxFlow / 140; // = 1.21 bei 170 m³/h
modifiers.nightBoostMultiplier = Math.min(modifiers.nightBoostMultiplier, maxMultiplier);

var baseBypassOpen  = flow.get('bypassOpenOffset')  || 1.0;
var baseBypassClose = flow.get('bypassCloseOffset') || 2.0;
var aggrFactor = modifiers.bypassAggressiveness * 0.3;
d.bypassOpenOffsetEffective  = Math.max(0.3, baseBypassOpen  - aggrFactor);
d.bypassCloseOffsetEffective = Math.max(1.0, baseBypassClose - aggrFactor);

d.forecastModifiers = modifiers;

if (modifiers.reason.length > 0) {
    node.status({ fill: 'blue', shape: 'dot', text: 'Forecast: ' + modifiers.reason.join(' | ') });
} else {
    node.status({ fill: 'grey', shape: 'ring', text: 'Kein Forecast-Modifier aktiv' });
}

msg.payload = d;
return msg;

// ══════════════════════════════════════════════════════════════
// STEP 2c: FENSTER-LÜFTUNGSEMPFEHLUNG
// Version: 1.0 — Push-Benachrichtigung bei Statuswechsel
// Aktivierung: flow.set('fensterHinweisEnabled', true)
// ══════════════════════════════════════════════════════════════

var p = msg.payload || {};
var enabled = flow.get('fensterHinweisEnabled') || false;
if (!enabled) return null;

var bypass = p.bypass || {};
var absHum = p.absHum || {};
var anfeuch = absHum.anfeuchtung || {};
var d = msg.sensorData || p;  // Fallback

// Werte aus Step 2 Output
var outdoorTemp = parseFloat(bypass.deltaT) ? (parseFloat(p.roomLog ? p.roomLog.match(/[\d.]+/) : 22) - parseFloat(bypass.deltaT)) : null;
var avgIndoorTemp = 0;
var rooms = (p.roomLog || '').match(/[\d.]+/g);
if (rooms && rooms.length > 0) {
    var sum = 0;
    rooms.forEach(function(t) { sum += parseFloat(t); });
    avgIndoorTemp = sum / rooms.length;
}

// Direkte Werte aus msg.sensorData (wenn verfügbar via Link-Node)
var sensorData = flow.get('kwl_last_sensor_data') || {};
var outTemp = sensorData.outdoorTemp || (avgIndoorTemp - parseFloat(bypass.deltaT || 0));
var absHumOut = parseFloat(absHum.out) || null;
var absHumIn = parseFloat(absHum.innenMin) || null;
var taupunktSicher = anfeuch.taupunktSicher !== false;
var isNight = p.isNight || false;

// Temperatur-Delta
var deltaT = avgIndoorTemp - outTemp;

// Feuchte-Check: Außen darf nicht viel feuchter sein als innen
var feuchteOk = true;
if (absHumOut !== null && absHumIn !== null) {
    feuchteOk = absHumOut <= absHumIn + 1.5;  // max 1.5 g/m³ feuchter
}

// Empfehlung berechnen
var empfehlung;
var icon;
var details;

if (deltaT >= 3 && feuchteOk && taupunktSicher && !isNight) {
    empfehlung = 'OFFEN';
    icon = '🟢';
    details = 'Fenster ganz öffnen! Außen ' + outTemp.toFixed(0) + '°C (' + deltaT.toFixed(1) + 'K kühler), Feuchte ok.';
} else if (deltaT >= 1 && feuchteOk && taupunktSicher) {
    empfehlung = 'KIPP';
    icon = '🟡';
    details = 'Kipplüftung möglich. Außen ' + outTemp.toFixed(0) + '°C (' + deltaT.toFixed(1) + 'K kühler).';
    if (isNight) details += ' Nachts nur kippen.';
} else if (deltaT < 0) {
    empfehlung = 'ZU';
    icon = '🔴';
    details = 'Fenster zu! Außen wärmer (' + outTemp.toFixed(0) + '°C) als innen (' + avgIndoorTemp.toFixed(0) + '°C).';
} else if (!feuchteOk) {
    empfehlung = 'ZU';
    icon = '🔴';
    details = 'Fenster zu! Außenluft zu feucht (AH ' + (absHumOut || '?').toFixed(1) + ' > innen ' + (absHumIn || '?').toFixed(1) + ' g/m³).';
} else if (!taupunktSicher) {
    empfehlung = 'ZU';
    icon = '🔴';
    details = 'Fenster zu! Kondensationsgefahr (Außentemp unter Taupunkt).';
} else {
    empfehlung = 'KIPP';
    icon = '🟡';
    details = 'Kurz Kipplüften ok, aber kein Dauerlüften. Delta nur ' + deltaT.toFixed(1) + 'K.';
}

// Nur bei Statuswechsel benachrichtigen
var lastEmpfehlung = context.get('lastEmpfehlung') || '';
if (empfehlung === lastEmpfehlung) return null;
context.set('lastEmpfehlung', empfehlung);

// Cooldown: Nicht öfter als alle 30 Min benachrichtigen
var lastNotify = context.get('lastNotifyTime') || 0;
var nowMs = Date.now();
if (nowMs - lastNotify < 1800000) return null;  // 30 Min Cooldown
context.set('lastNotifyTime', nowMs);

// Push-Nachricht
msg.payload = {
    title: icon + ' Lüftungsempfehlung: ' + empfehlung,
    message: details
};

node.status({ fill: empfehlung === 'OFFEN' ? 'green' : empfehlung === 'KIPP' ? 'yellow' : 'red',
    shape: 'dot', text: icon + ' ' + empfehlung + ' | ' + details.substring(0, 50) });

return msg;

// ══════════════════════════════════════════════════════════════
// STEUERUNG AUS — Alles auf Normalwerte zurücksetzen
// Setzt: Modus Manuell (1), Flow 150 m³/h, Bypass-Schwelle 23°C
// Deaktiviert die Automatik bis manueller Re-Start
// ══════════════════════════════════════════════════════════════

var HA_URL = flow.get('haUrl') || 'http://homeassistant.local:8123';
var HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken');
var MODBUS_HUB = flow.get('modbusHub') || 'Maico KWL';

// Automatik deaktivieren
flow.set('kwl_auto_disabled', true);

// Normalwerte
var commands = [
    { address: 550, value: 1,   desc: 'Modus → Manuell' },
    { address: 155, value: 150, desc: 'Flow → 150 m³/h' },
    { address: 302, value: 230, desc: 'Bypass-Schwelle → 23.0°C' },
    { address: 552, value: 1,   desc: 'Bypass-Saison → ein' }
];

// Queue aufbauen
flow.set('kwl_api_queue', commands.slice(1));
flow.set('kwl_api_total', commands.length);
flow.set('kwl_api_done', 0);

// Context zurücksetzen damit nächster Auto-Start sauber ist
context.set('lastMode', 1);
context.set('lastFlowRate', 150);
context.set('lastRoomTempMax', 230);

var first = commands[0];
msg.url = HA_URL + '/api/services/modbus/write_register';
msg.method = 'POST';
msg.headers = { 'Authorization': 'Bearer ' + HA_TOKEN, 'Content-Type': 'application/json' };
msg.payload = { hub: MODBUS_HUB, slave: 1, address: first.address, value: [first.value] };

node.warn('⏹️ KWL Steuerung AUS — Normalwerte gesetzt');
node.status({ fill: 'red', shape: 'ring', text: 'AUS — Manuell 150 m³/h, Bypass 23°C' });

// Push-Benachrichtigung
var notifyMsg = {
    payload: {
        title: '⏹️ KWL Steuerung AUS',
        message: 'Automatik deaktiviert. Manuell / 150 m³/h / Bypass 23°C'
    }
};

return [msg, notifyMsg];

var p = msg.payload || {};
var HA_URL = flow.get('haUrl');
var HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken');

var isManualTrigger = (msg.topic === 'click' || msg.topic === 'trigger' || p.forced === true);
//var forceLog = (p.bypass && p.bypass.effektiv === false && p.bypass.wanted === true);

function f(val, n) {
    var num = parseFloat(val);
   return isNaN(num) ? '?' : num.toFixed(n !== undefined ? n : 1);
}

var regLabels = {
    550: 'Mode',
    552: 'Bypass-Saison',
    302: 'Bypass-Temp',
    155: 'Volumenstrom',
    154: 'Flow-Red',
    156: 'Flow-Int',
    554: 'Stufe'
};
var modeLabels = { 0: 'Aus', 1: 'Manuell', 2: 'AutoZeit', 3: 'AutoSensor', 4: 'Eco-Zu', 5: 'Eco-Ab' };

var actions = [];
(p.commands || []).forEach(function (cmd) {
    var label = regLabels[cmd.register] || ('Reg' + cmd.register);
    var val = cmd.value;
    if (cmd.register === 550) val = (modeLabels[cmd.value] || cmd.value);
    if (cmd.register === 552) val = (cmd.value === 1 ? 'ein' : 'aus');
    if (cmd.register === 302) val = (cmd.value / 10).toFixed(1) + '°C';
    if (cmd.register === 155 || cmd.register === 154 || cmd.register === 156) val = cmd.value + 'm³/h';
    actions.push(label + '→' + val);
});
var actionText = actions.length > 0 ? actions.join(', ') : 'keine';

// ── Sollwert-Bildung berechnen ──
var flowReasonsArray = (p.flowRate && p.flowRate.reasons) || [];
var finalFlow = parseInt(p.flowRate && p.flowRate.new) || 100;
var ahCap = parseInt(p.flowRate && p.flowRate.ahCap) || 999; 
var flowCalculationText = '';

if (flowReasonsArray.length > 0) {
    var rawSum = 100;
    flowReasonsArray.forEach(function(reasonStr) {
        var match = reasonStr.match(/[+-]\s*(\d+)/);
        if (match) {
            var val = parseInt(match[1]);
            if (reasonStr.indexOf('-') !== -1) rawSum -= val;
            else rawSum += val;
        }
    });
    if (rawSum > ahCap) {
        flowReasonsArray.push('Cap-Bremse: -' + (rawSum - ahCap));
    }
    flowCalculationText = '100 → [' + flowReasonsArray.join(' | ') + '] → ' + finalFlow + ' m³/h';
} else {
    flowCalculationText = finalFlow + ' m³/h (Standard)';
}

var absHum = p.absHum || {};
var bypass = p.bypass || {};
var anfeuch = absHum.anfeuchtung || {};

// ── OPTIMIERUNG: Kompakter Feuchte-Text ──
var anfeuchtStatus = 'ok';
if (anfeuch.notfall) anfeuchtStatus = 'NOTFALL 🚨';
else if (anfeuch.kritisch) anfeuchtStatus = 'kritisch ⚠️';
else if (anfeuch.nochNoetig) anfeuchtStatus = 'aktiv 🔄';

var humidityText = anfeuchtStatus + ' (W: ' + f(absHum.in, 1) + ' | K: ' + f(absHum.kinder, 1) + ' | A: ' + f(absHum.out, 1) + ' g/m³)';

// ── Fenster-Logik ──
var sensorData = flow.get('kwl_last_sensor_data') || {};
var outTemp = sensorData.outdoorTemp || 0;
var avgIndoorTemp = 0;
var roomCount = 0;
(sensorData.rooms || []).forEach(function (r) { avgIndoorTemp += r.temp; roomCount++; });
if (roomCount > 0) avgIndoorTemp = avgIndoorTemp / roomCount;

var absHumOut = parseFloat(absHum.out) || null;
var absHumIn = parseFloat(absHum.innenMin) || null;
var taupunktSicher = anfeuch.taupunktSicher !== false;
var isNight = p.isNight || false;
var deltaT = avgIndoorTemp - outTemp;
var feuchteOk = (absHumOut !== null && absHumIn !== null) ? (absHumOut <= absHumIn + 1.5) : true;

var fensterIcon = '🟡';
var fensterText = 'Kipp ok (' + deltaT.toFixed(0) + 'K)';
if (deltaT >= 3 && feuchteOk && taupunktSicher && !isNight) {
    fensterIcon = '🟢'; fensterText = 'Öffnen ok (' + deltaT.toFixed(0) + 'K kühler)';
} else if (deltaT < 0 || !feuchteOk || !taupunktSicher) {
    fensterIcon = '🔴';
    fensterText = !feuchteOk ? 'Zu lassen! (außen feucht)' : (!taupunktSicher ? 'Zu lassen! (Kondensation)' : 'Zu lassen! (außen wärmer)');
}

var bypassEffektivText = '-';
if (bypass.wanted && bypass.effektiv === true) bypassEffektivText = 'JA';
else if (bypass.wanted && bypass.effektiv === false) bypassEffektivText = 'NEIN!';

// ── Das neue, vollständige Log-Design ──
var cleanLogMessage = [
    '💨 SOLLWERT: ' + flowCalculationText,
    '🕹️ LOGIK: ' + (p.mode && p.mode.name || '?') + ' (' + (p.mode && p.mode.reason || '?') + ')',
    '💧 FEUCHTE: ' + humidityText,
    '⚡ AKTION: ' + actionText,
    '🪟 FENSTER: ' + fensterIcon + ' ' + fensterText,
    '🔄 BYPASS: ' + (bypass.wanted ? 'OFFEN' : 'ZU') + ' (Effektiv: ' + bypassEffektivText + ')'
].join('   ❘   ');

msg.url = HA_URL + '/api/services/logbook/log';
msg.method = 'POST';
msg.headers = { 'Authorization': 'Bearer ' + HA_TOKEN, 'Content-Type': 'application/json' };

msg.payload = {
    name: 'KWL Steuerung',
    message: cleanLogMessage, 
    entity_id: 'sensor.maico_betriebsart',
    domain: 'kwl'
};

return msg;

// ══════════════════════════════════════════════════════════════
// STEP 1c: Register 707 — Raumtemperatur an Maico melden
// Schreibt die HÖCHSTE Raumtemperatur auf Reg.707
// Maico-Vorgabe: Schreibzyklus min. 10 Minuten!
// Ersetzt die HA-Automation "WS300 Modbus Sync2"
//
// Maico-interne Bypass-Logik:
//   Bypass öffnet wenn Reg.707 > Reg.302
//   → Deshalb immer den wärmsten Raum melden
//
// Verkabelung: Step 1 (Sensordaten) → Step 1c → eigener HTTP Request Node
// ══════════════════════════════════════════════════════════════

var d = msg.payload || {};
var rooms = d.rooms || [];

if (rooms.length === 0) return null;

// ── 5-Minuten-Sperre (Maico Modbus Doku: Schreibzyklus min. 10min) ──
var MIN_WRITE_INTERVAL = 300000; // 5 Minuten in ms
var lastWriteTime = context.get('lastReg707Time') || 0;
var nowMs = Date.now();

if (nowMs - lastWriteTime < MIN_WRITE_INTERVAL) {
    node.status({
        fill: 'grey', shape: 'ring',
        text: 'Warte... ' + Math.round((MIN_WRITE_INTERVAL - (nowMs - lastWriteTime)) / 60000) + ' min bis nächster Schreibzyklus'
    });
    return null;
}

// ── Höchste Raumtemperatur ermitteln ──
var maxRoomTemp = Math.max.apply(null, rooms.map(function (r) { return r.temp; }));
var maxRoomName = '';
rooms.forEach(function (r) { if (r.temp === maxRoomTemp) maxRoomName = r.name; });

var reg707Value = Math.round(maxRoomTemp * 10);

// ── Plausibilitätsprüfung (Maico akzeptiert -300 bis 1200 = -30°C bis 120°C) ──
if (reg707Value < -300 || reg707Value > 1200) {
    node.warn('Reg.707 außerhalb Bereich: ' + reg707Value + ' (' + maxRoomTemp.toFixed(1) + '°C)');
    return null;
}

// ── Hysterese: Nur senden wenn Änderung > ±0.5°C ──
var lastSent = context.get('lastReg707') || 0;
if (Math.abs(reg707Value - lastSent) < 5) {
    node.status({
        fill: 'green', shape: 'ring',
        text: maxRoomName + ': ' + maxRoomTemp.toFixed(1) + '°C (unverändert)'
    });
    return null;
}

// ── Rücklese-Validierung (optional: prüft ob letzter Wert angekommen ist) ──
var states = global.get('homeassistant.homeAssistant.states') || {};
var readback = states['sensor.maico_t_raum_bus'];
var readbackValue = readback ? Math.round(parseFloat(readback.state) * 10) : null;

if (readbackValue !== null && lastSent !== 0 && Math.abs(readbackValue - lastSent) > 5) {
    node.warn('⚠️ Reg.707 Mismatch: geschrieben ' + lastSent + ' (' + (lastSent / 10).toFixed(1) + '°C), gelesen ' + readbackValue + ' (' + (readbackValue / 10).toFixed(1) + '°C)');
}

// ── Schreiben ──
context.set('lastReg707', reg707Value);
context.set('lastReg707Time', nowMs);

var HA_URL = flow.get('haUrl') || 'http://homeassistant.local:8123';
var HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken');
var MODBUS_HUB = flow.get('modbusHub') || 'Maico KWL';

msg.url = HA_URL + '/api/services/modbus/write_register';
msg.method = 'POST';
msg.headers = { 'Authorization': 'Bearer ' + HA_TOKEN, 'Content-Type': 'application/json' };
msg.payload = { hub: MODBUS_HUB, slave: 1, address: 707, value: [reg707Value] };

node.status({
    fill: 'green', shape: 'dot',
    text: maxRoomName + ': ' + maxRoomTemp.toFixed(1) + '°C → Reg.707=' + reg707Value + ' (' + new Date().toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' }) + ')'
});

return msg;
